func SendFeedbackEmail(smtpHost string, smtpPort string, auth smtp.Auth, fromAddr string, toAddr string, emailBody string) error {
	addr := smtpHost + ":" + smtpPort
	err := smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}
	return nil
}

