	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize inputs to prevent email header injection.
	// Remove any CR/LF characters from values that will be placed in headers.
	sanitizedSubject := sanitizeHeaderValue(subject)
	sanitizedFromAddr := sanitizeHeaderValue(fromAddr)
	sanitizedToAddr := sanitizeHeaderValue(toAddr)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		sanitizedFromAddr,
		sanitizedToAddr,
		emailSubject,
	)

	// Escape user-provided values to prevent HTML injection / XSS
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped user inputs
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// sanitizeHeaderValue removes CR and LF characters from a string
// to prevent email header injection attacks.
func sanitizeHeaderValue(value string) string {
	value = strings.ReplaceAll(value, "\r", "")
	value = strings.ReplaceAll(value, "\n", "")
	return value
}

func main() {
	// Example usage
	email, err := BuildFeedbackEmail(
		"user@example.com",
		"support@example.com",
		"John Doe",
		"Login Issue",
		"I can't log in to my account. Please help!",
	)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Println(email)
}

